import type { CareerQuestion } from "./social-worker-questions";

export const socialWorkerQuestionsBatch10: CareerQuestion[] = [
  { id: "sw-501", stem: "A social worker is using the Person-in-Environment perspective to assess a client experiencing homelessness. Which factors should be assessed?", options: ["Only the client's mental health symptoms", "The interaction between individual factors (mental health, substance use, coping), relational factors (family, social support), and environmental factors (housing market, employment, policies, discrimination)", "Only the client's employment history", "Only the available shelter beds in the community"], correctIndex: 1, rationale: "The PIE perspective examines the reciprocal relationship between individuals and their environments. For a client experiencing homelessness, this includes assessing individual needs, interpersonal relationships, community resources, and systemic barriers. This holistic assessment prevents reducing complex social problems to individual pathology.", difficulty: 2, category: "Assessment & Intervention Planning", topic: "PIE Assessment", questionType: "PRIORITIZATION" },
  { id: "sw-502", stem: "A social worker learns that their client's child has been exposed to lead paint in their rental housing. This is an example of:", options: ["A personal health behavior issue", "Environmental injustice—where low-income and marginalized communities disproportionately face environmental health hazards that cause preventable illness", "A cosmetic concern", "An issue outside social work scope"], correctIndex: 1, rationale: "Lead exposure disproportionately affects children in low-income housing, particularly communities of color. Lead poisoning causes irreversible neurological damage. Social workers should advocate for safe housing, connect families with lead abatement resources, ensure children receive blood lead testing, and advocate for policy changes requiring lead-safe housing standards.", difficulty: 2, category: "Social Determinants of Health", topic: "Environmental Health", questionType: "MCQ" },
  { id: "sw-503", stem: "A social worker is facilitating a psychoeducational group for newly diagnosed diabetes patients. The MOST appropriate group format is:", options: ["Unstructured, open-ended discussion", "A structured curriculum covering disease management, lifestyle modifications, medication adherence, emotional adjustment, and community resources with opportunities for peer support", "Individual therapy within a group setting", "A confrontational approach to motivate behavior change"], correctIndex: 1, rationale: "Psychoeducational groups use structured curricula to provide information, build skills, and offer peer support around a specific condition. For diabetes, this includes disease education, dietary management, exercise, medication adherence, blood glucose monitoring, emotional adjustment, and accessing community resources. The group format provides normalization and peer learning.", difficulty: 2, category: "Group Work", topic: "Health Education Groups", questionType: "MCQ" },
  { id: "sw-504", stem: "What is the 'holding environment' concept from Winnicott's object relations theory?", options: ["Physical restraint of agitated clients", "A safe, consistent therapeutic space where the client feels contained, supported, and secure enough to explore difficult emotions and experiences without fear of judgment or abandonment", "The waiting room of a therapy office", "A seclusion room in a psychiatric facility"], correctIndex: 1, rationale: "Winnicott's 'holding environment' metaphorically extends the concept of a mother's physical and emotional holding of an infant to the therapeutic relationship. The therapist creates a safe, consistent, reliable space where the client can experience and process difficult emotions. This concept underpins trauma-informed practice and the creation of therapeutic safety across all modalities.", difficulty: 3, category: "Clinical Practice", topic: "Object Relations", questionType: "CASE_VIGNETTE" },
  { id: "sw-505", stem: "Crisis theory suggests that a crisis presents both danger and:", options: ["Chronic illness", "Opportunity—the disequilibrium created by crisis can lead to new coping skills, personal growth, and higher functioning than the pre-crisis state", "Legal liability", "Professional burnout"], correctIndex: 1, rationale: "The Chinese characters often cited for 'crisis' represent both danger and opportunity. Crisis theory (Caplan, Lindemann) posits that the disequilibrium created by crisis, while distressing, creates conditions for change. With effective intervention, individuals can develop new coping skills, resolve previously unaddressed issues, and achieve a higher level of functioning than before the crisis.", difficulty: 2, category: "Crisis Intervention", topic: "Crisis as Opportunity", questionType: "CASE_VIGNETTE" },
  { id: "sw-506", stem: "Compassion fatigue in social work is best understood as:", options: ["Physical exhaustion from too many work hours", "The emotional and physical exhaustion resulting from chronic use of empathy in helping others who are suffering, combining elements of burnout and secondary traumatic stress", "Fatigue from showing too much sympathy", "A sign of professional weakness"], correctIndex: 1, rationale: "Compassion fatigue (Charles Figley) is the cumulative toll of helping those who suffer. It combines burnout (work-related exhaustion) with secondary traumatic stress (absorption of others' traumatic material). Symptoms include emotional exhaustion, reduced empathy, detachment, intrusive imagery, and decreased professional effectiveness. Prevention includes self-care, supervision, workload management, and organizational support.", difficulty: 2, category: "Safeguarding & Risk Management", topic: "Compassion Fatigue", questionType: "PRIORITIZATION" },
  { id: "sw-507", stem: "A social worker is using evidence-based practice and finds conflicting research results about an intervention. What should they do?", options: ["Choose the study with the largest sample size", "Critically evaluate the quality, relevance, and applicability of each study, consult systematic reviews when available, consider the client's specific context, and make a clinical judgment integrating all available evidence", "Discard all research and rely on clinical intuition", "Use whichever intervention they prefer"], correctIndex: 1, rationale: "When research findings conflict, social workers should: evaluate study quality (methodology, sample size, bias risk), check for systematic reviews that synthesize multiple studies, consider the relevance to their specific client population, consult clinical practice guidelines, seek expert consultation, and integrate research evidence with clinical expertise and client preferences.", difficulty: 3, category: "Assessment & Intervention Planning", topic: "Critical Appraisal", questionType: "PRIORITIZATION" },
  { id: "sw-508", stem: "What is the difference between mediation and arbitration in conflict resolution?", options: ["They are the same process", "In mediation, a neutral third party facilitates negotiation between parties who retain decision-making power; in arbitration, the third party makes a binding decision", "Mediation always produces a binding decision", "Arbitration is always voluntary"], correctIndex: 1, rationale: "Mediation is a facilitated negotiation where the mediator helps parties communicate and reach their own agreement. The mediator does not impose solutions. Arbitration involves a third party who hears both sides and makes a binding decision. Social workers often serve as mediators in family, community, and workplace disputes, using their interpersonal skills to facilitate resolution.", difficulty: 2, category: "Communication & Interviewing", topic: "Conflict Resolution", questionType: "CASE_VIGNETTE" },
  { id: "sw-509", stem: "A social worker is supporting an adolescent who identifies as non-binary. The MOST affirming approach is:", options: ["Using the adolescent's birth name and assigned gender pronouns", "Using the adolescent's chosen name and pronouns, creating a supportive therapeutic environment, and addressing the impact of gender minority stress while supporting identity exploration", "Telling the adolescent it's a phase", "Referring to a conversion therapist"], correctIndex: 1, rationale: "Affirming practice with non-binary youth includes: using chosen name/pronouns, creating a safe therapeutic environment, understanding the minority stress model, supporting identity exploration without imposing a trajectory, addressing family dynamics, connecting to LGBTQ+ community resources, and advocating for gender-affirming policies in schools and other settings. Conversion therapy is harmful and unethical.", difficulty: 2, category: "DEI & Anti-Oppressive Practice", topic: "Gender-Affirming Practice", questionType: "CASE_VIGNETTE" },
  { id: "sw-510", stem: "A social worker discovers a colleague is intoxicated during work hours. What is the ethical obligation?", options: ["Ignore it to protect the colleague's reputation", "Address the concern directly with the colleague and/or report to a supervisor, as the primary obligation is to protect clients from potential harm by an impaired professional", "Wait to see if it happens again", "Report directly to the licensing board without discussing with the colleague"], correctIndex: 1, rationale: "The NASW Code of Ethics requires social workers to address colleague impairment. An intoxicated colleague poses immediate risk to clients. The social worker should address the situation promptly—directly with the colleague if safe and appropriate, and with supervisory authority. Client safety takes priority over collegial loyalty. Documentation and follow-up are essential.", difficulty: 2, category: "Ethics & Boundaries", topic: "Colleague Impairment", questionType: "ETHICS_SCENARIO" },
  { id: "sw-511", stem: "A social worker is working in a Federally Qualified Health Center (FQHC). The social worker's primary role involves:", options: ["Only providing therapy to insured patients", "Delivering integrated behavioral health services to underserved populations, addressing social determinants of health, coordinating care, and providing brief interventions within the primary care setting", "Managing the center's finances", "Providing only administrative support"], correctIndex: 1, rationale: "FQHCs serve medically underserved communities. Social workers in FQHCs provide integrated behavioral health services, screen for social needs (housing, food, transportation), coordinate care, deliver brief evidence-based interventions, support chronic disease management, and connect patients to community resources. The social worker bridges medical and psychosocial needs in a population health framework.", difficulty: 2, category: "Interdisciplinary Collaboration", topic: "FQHC Practice", questionType: "MCQ" },
  { id: "sw-512", stem: "The bio-ecological model of human development (Bronfenbrenner) includes which nested systems?", options: ["Only the family system", "Microsystem, mesosystem, exosystem, macrosystem, and chronosystem—representing layers of environmental influence from immediate settings to cultural context and time", "Id, ego, and superego", "Conscious, preconscious, and unconscious"], correctIndex: 1, rationale: "Bronfenbrenner's model identifies five nested systems: microsystem (immediate settings—family, school), mesosystem (interactions between microsystems), exosystem (settings that indirectly affect the individual—parent's workplace), macrosystem (cultural values, laws, customs), and chronosystem (historical time and life transitions). This framework helps social workers understand the multiple levels of influence on human development.", difficulty: 2, category: "Clinical Practice", topic: "Ecological Systems", questionType: "CASE_VIGNETTE" },
  { id: "sw-513", stem: "What is trauma bonding and how does it relate to domestic violence?", options: ["A healthy attachment formed through shared adversity", "A psychological attachment formed through cycles of abuse and intermittent positive reinforcement that creates a powerful emotional bond making it difficult for victims to leave abusive relationships", "A therapeutic technique used in trauma treatment", "A bond between trauma survivors in group therapy"], correctIndex: 1, rationale: "Trauma bonding (Patrick Carnes) develops through the intermittent reinforcement pattern of abuse cycles: tension building, acute abuse, reconciliation/honeymoon, and calm. The unpredictable alternation of cruelty and kindness creates a powerful biochemical and emotional attachment. Understanding trauma bonding helps social workers respond with empathy rather than frustration when clients return to abusive relationships.", difficulty: 2, category: "Clinical Practice", topic: "Trauma Bonding", questionType: "CASE_VIGNETTE" },
  { id: "sw-514", stem: "A social worker is assessing cultural identity as part of a clinical assessment. Important components include:", options: ["Country of origin only", "Ethnic identity, acculturation level, language preference, religious/spiritual identity, gender identity, generational status, immigration experience, and the client's own understanding of how culture influences their health and help-seeking behavior", "Race categorization only", "What foods the client eats"], correctIndex: 1, rationale: "Cultural identity assessment is multidimensional, encompassing: ethnic/racial identity, acculturation/enculturation level, language use and preference, religion/spirituality, immigration history and documentation status, generational identity, cultural values and practices, and subjective cultural identification. The CFI (Cultural Formulation Interview) in the DSM-5 provides a structured approach.", difficulty: 2, category: "DEI & Anti-Oppressive Practice", topic: "Cultural Identity Assessment", questionType: "CASE_VIGNETTE" },
  { id: "sw-515", stem: "What is the concept of 'accompaniment' in social work with immigrant and refugee populations?", options: ["Physical accompaniment to appointments only", "A practice of walking alongside clients through complex systems by providing emotional support, system navigation, advocacy, and consistent presence throughout their journey—particularly during legal proceedings, medical visits, and social service encounters", "Acting as a translator only", "Escorting clients to their home country"], correctIndex: 1, rationale: "Accompaniment extends beyond referral to actively supporting clients through intimidating systems. For immigrant/refugee populations, this may include attending immigration hearings, navigating healthcare systems, advocating in school meetings, and providing consistent supportive presence. This practice reduces barriers, builds trust, and demonstrates the social work commitment to 'starting where the client is.'", difficulty: 2, category: "DEI & Anti-Oppressive Practice", topic: "Accompaniment Practice", questionType: "CASE_VIGNETTE" },
  { id: "sw-516", stem: "A social worker is helping develop a community health worker (CHW) program. CHWs are:", options: ["Licensed clinical professionals", "Trusted community members who serve as bridges between health/social services and the community, providing outreach, education, advocacy, and culturally appropriate support", "Volunteers with no training", "Replacement for social workers"], correctIndex: 1, rationale: "Community health workers are trusted community members who bridge gaps between communities and health/social service systems. They provide culturally appropriate health education, outreach, system navigation, advocacy, and social support. CHW programs improve health outcomes, reduce disparities, and are cost-effective. Social workers often develop, supervise, and partner with CHW programs.", difficulty: 2, category: "Community Practice", topic: "Community Health Workers", questionType: "MCQ" },
  { id: "sw-517", stem: "Narrative exposure therapy (NET) is particularly effective for:", options: ["Personality disorders", "Refugees and survivors of organized violence who have experienced multiple traumatic events, integrating trauma processing within a chronological life narrative", "Substance use disorders as primary treatment", "Children under age 5"], correctIndex: 1, rationale: "NET was developed specifically for survivors of organized violence and refugees with multiple traumatic experiences. It creates a chronological life narrative that contextualizes traumatic events within the person's life story. This approach helps integrate fragmented trauma memories, provides testimony that can be used for advocacy purposes, and is effective in settings with limited mental health resources.", difficulty: 3, category: "Trauma-Informed Care", topic: "Narrative Exposure Therapy", questionType: "CASE_VIGNETTE" },
  { id: "sw-518", stem: "A social worker notices patterns of institutional racism in their agency's policies. An anti-racist response would include:", options: ["Ignoring the patterns to avoid conflict", "Documenting the disparate impacts, raising concerns through appropriate channels, proposing specific policy changes, building coalitions with affected community members, and holding the organization accountable", "Leaving the agency silently", "Only addressing individual acts of racism"], correctIndex: 1, rationale: "Anti-racist practice requires addressing racism at all levels—not just individual but institutional and structural. Social workers should document evidence of disparate impact, use data to support concerns, propose concrete alternatives, build coalitions within and outside the organization, and hold leadership accountable for equitable outcomes. This goes beyond diversity training to structural change.", difficulty: 3, category: "DEI & Anti-Oppressive Practice", topic: "Institutional Anti-Racism", questionType: "CASE_VIGNETTE" },
  { id: "sw-519", stem: "Restorative justice in social work practice differs from punitive justice in that:", options: ["It is more punitive than traditional justice", "It focuses on repairing harm through inclusive dialogue between victim, offender, and community, emphasizing accountability, healing, and relationship restoration rather than punishment", "It eliminates all consequences for harmful behavior", "It only applies to minor offenses"], correctIndex: 1, rationale: "Restorative justice shifts focus from punishment to repair. Key elements include: acknowledging harm, understanding impact on victims, taking responsibility, making amends, and reintegrating offenders into the community. Social workers facilitate restorative circles, victim-offender mediation, and community conferencing. Research supports restorative justice for reducing recidivism and increasing victim satisfaction.", difficulty: 2, category: "Community Practice", topic: "Restorative Justice", questionType: "MCQ" },
  { id: "sw-520", stem: "A social worker is treating a client with hoarding disorder. Which treatment approach has the strongest evidence?", options: ["Simply cleaning out the client's home", "CBT specifically adapted for hoarding that addresses cognitive distortions about possessions, emotional attachment to items, and gradually practices discarding with behavioral experiments", "Psychoanalysis to understand the unconscious meaning of hoarding", "Medication as the sole intervention"], correctIndex: 1, rationale: "Hoarding-specific CBT (Steketee & Frost) addresses the unique cognitive and behavioral features of hoarding: difficulty discarding due to emotional attachment, distorted beliefs about possessions (responsibility, waste prevention), information processing deficits, and avoidance. Treatment includes motivational enhancement, cognitive restructuring, skills training (organizing, decision-making), and in-home sorting practice.", difficulty: 2, category: "Mental Health", topic: "Hoarding Disorder", questionType: "CASE_VIGNETTE" },
  { id: "sw-521", stem: "Dialectical thinking in DBT refers to:", options: ["Arguing with the client", "The ability to hold two seemingly contradictory truths simultaneously—such as accepting yourself as you are AND working to change—finding synthesis rather than choosing one extreme", "Thinking about two problems at once", "Diagnosing two disorders simultaneously"], correctIndex: 1, rationale: "Dialectics is the philosophical foundation of DBT. The core dialectic is acceptance AND change—validating the client's current experience while encouraging growth. Dialectical thinking moves beyond 'either/or' to 'both/and,' seeking synthesis of apparent opposites. This reduces the rigid, all-or-nothing thinking common in BPD and promotes cognitive flexibility.", difficulty: 2, category: "Clinical Practice", topic: "Dialectical Thinking", questionType: "CASE_VIGNETTE" },
  { id: "sw-522", stem: "A social worker is conducting an initial assessment with a new client. The FIRST priority in the first session is:", options: ["Completing all assessment paperwork", "Building rapport and establishing safety, explaining the therapeutic process and confidentiality, and beginning to understand the client's concerns and goals", "Making a diagnosis", "Developing a treatment plan"], correctIndex: 1, rationale: "The first session prioritizes relationship building and orientation. Key tasks include: creating a safe, welcoming environment, explaining the therapeutic process, discussing confidentiality and its limits, beginning to understand the client's perspective and concerns, assessing for immediate safety, and beginning to build the therapeutic alliance. Rushing to diagnosis or treatment planning undermines engagement.", difficulty: 1, category: "Communication & Interviewing", topic: "Initial Session", questionType: "CASE_VIGNETTE" },
  { id: "sw-523", stem: "An elderly client is showing signs of self-neglect—not eating properly, living in unsanitary conditions, and refusing help. This situation requires:", options: ["Immediate involuntary placement", "Assessment of the client's decision-making capacity, exploration of reasons for self-neglect, respectful engagement with the client's autonomy while assessing safety risks, and graduated intervention from least to most restrictive", "Accepting the client's choices without assessment", "Calling adult protective services without assessing capacity"], correctIndex: 1, rationale: "Self-neglect in elderly clients requires careful balancing of autonomy and safety. Assessment should include: capacity evaluation, exploration of underlying causes (depression, dementia, physical disability, loss, financial barriers), risk assessment, and graduated intervention. A competent client has the right to make choices others disagree with. Support services should be offered without coercion unless the client lacks capacity.", difficulty: 3, category: "Gerontology", topic: "Self-Neglect", questionType: "CASE_VIGNETTE" },
  { id: "sw-524", stem: "What is the role of the social worker in an Individualized Education Program (IEP) meeting?", options: ["Writing the academic curriculum", "Contributing social-emotional assessment data, developing social-emotional and behavioral goals, recommending school-based services, and advocating for the student's comprehensive needs within the educational team", "Serving as the school principal's representative", "Only observing without contributing"], correctIndex: 1, rationale: "School social workers are integral IEP team members who contribute: social-emotional and behavioral assessment data, identification of environmental factors affecting learning, social-emotional and behavioral goal development, recommendations for school-based counseling and support services, family engagement strategies, and community resource linkage.", difficulty: 2, category: "School & Social Service Systems", topic: "IEP Role", questionType: "MCQ" },
  { id: "sw-525", stem: "What ethical considerations apply when a social worker uses artificial intelligence tools in clinical practice?", options: ["AI tools have no ethical implications", "Social workers must ensure AI tools do not replace clinical judgment, protect client privacy in AI systems, assess AI tools for bias, obtain informed consent about AI use, and maintain responsibility for clinical decisions even when using AI-assisted tools", "AI should make all clinical decisions", "Social workers should avoid all technology"], correctIndex: 1, rationale: "As AI becomes integrated into clinical practice, social workers must: evaluate AI tools for potential bias, ensure client data privacy and security, obtain informed consent regarding AI use, maintain professional responsibility for clinical decisions, critically evaluate AI recommendations, and ensure AI tools align with social work values of equity and self-determination.", difficulty: 3, category: "Ethics & Boundaries", topic: "AI Ethics", questionType: "ETHICS_SCENARIO" },
  { id: "sw-526", stem: "Acceptance and Commitment Therapy (ACT) uses the concept of 'cognitive defusion.' This means:", options: ["Removing all thoughts from the mind", "Learning to observe thoughts as mental events rather than literal truths, reducing their power over behavior by creating distance between the person and their thoughts", "Fusing thoughts together for clarity", "Ignoring all cognitive processes"], correctIndex: 1, rationale: "Cognitive defusion techniques help clients step back from their thoughts, seeing them as passing mental events rather than accurate reflections of reality. Techniques include: repeating a thought rapidly until it loses meaning, prefacing thoughts with 'I notice I'm having the thought that...', visualizing thoughts on leaves floating down a stream. This reduces thought-behavior fusion without trying to change thought content.", difficulty: 2, category: "Clinical Practice", topic: "ACT Defusion", questionType: "CASE_VIGNETTE" },
  { id: "sw-527", stem: "A social worker encounters a situation not explicitly addressed by the NASW Code of Ethics. What should they do?", options: ["Act based solely on personal values", "Apply the ethical principles and values from the Code through an ethical decision-making framework, consult with colleagues and supervisors, and consider relevant laws and professional standards", "Refuse to act until the Code is updated", "Do whatever the agency requires"], correctIndex: 1, rationale: "The NASW Code of Ethics provides principles and values, not answers to every situation. When facing novel ethical situations, social workers should: identify the relevant ethical principles, apply an ethical decision-making model, consult with supervisors and colleagues, consider legal requirements, review relevant literature, and make a reasoned decision aligned with professional values. Documentation of the decision-making process is essential.", difficulty: 2, category: "Ethics & Boundaries", topic: "Ethical Decision-Making Framework", questionType: "ETHICS_SCENARIO" },
  { id: "sw-528", stem: "A social worker is working with a client who has chronic pain and co-occurring depression. Which treatment model is MOST appropriate?", options: ["Treating pain and depression separately with different providers", "An integrated biopsychosocial approach that addresses the reciprocal relationship between pain and depression through CBT for pain management, behavioral activation, and coordination with medical pain management", "Ignoring the pain and treating only the depression", "Only referring to a pain management specialist"], correctIndex: 1, rationale: "Chronic pain and depression have a bidirectional relationship—pain worsens depression and depression amplifies pain perception. An integrated approach addresses both simultaneously through: CBT for pain management (activity pacing, cognitive restructuring of pain catastrophizing), behavioral activation, relaxation training, mindfulness-based stress reduction, and coordination with medical providers for pain management.", difficulty: 2, category: "Assessment & Intervention Planning", topic: "Comorbid Pain and Depression", questionType: "PRIORITIZATION" },
  { id: "sw-529", stem: "In child welfare, 'reasonable efforts' refers to:", options: ["Minimal attempts to help the family", "The legal requirement for child welfare agencies to make genuine, diligent efforts to prevent removal, reunify families, or achieve other permanency goals before pursuing more restrictive options", "Reasonable work hours for social workers", "Efforts to keep the case file organized"], correctIndex: 1, rationale: "Federal law requires child welfare agencies to make 'reasonable efforts' to: prevent removal of children from their homes, reunify families when removal occurs, and achieve permanency in a timely manner. Reasonable efforts include providing services (substance abuse treatment, parenting education, housing assistance, mental health services), making referrals, and documenting all efforts. Courts review whether reasonable efforts were made.", difficulty: 2, category: "Child & Family Services", topic: "Reasonable Efforts", questionType: "CASE_VIGNETTE" },
  { id: "sw-530", stem: "A social worker is helping a client who has aged out of foster care and is now experiencing homelessness. Which program provides federal support for this population?", options: ["TANF only", "The John H. Chafee Foster Care Program for Successful Transition to Adulthood, which provides education, training, employment, housing, and other support services for youth transitioning from foster care", "Social Security Retirement Benefits", "The Older Americans Act"], correctIndex: 1, rationale: "The Chafee program (formerly Foster Care Independence Program) provides federal funding for services supporting youth aging out of foster care (and formerly in care up to age 23). Services include: education and training vouchers, housing assistance, employment support, financial literacy, health insurance (Medicaid extension to age 26 in many states), and mentoring. Social workers should connect eligible youth to these resources.", difficulty: 2, category: "Child & Family Services", topic: "Chafee Program", questionType: "CASE_VIGNETTE" },
  { id: "sw-531", stem: "A social worker is developing cultural safety practices in their agency. Cultural safety goes beyond cultural competence by:", options: ["Being identical to cultural competence", "Shifting focus from the practitioner's knowledge about cultures to examining how power imbalances and institutional practices create unsafe environments for marginalized groups, requiring systemic change", "Ignoring cultural differences", "Only focusing on the practitioner's cultural awareness"], correctIndex: 1, rationale: "Cultural safety (originally from Maori nursing in New Zealand) goes beyond cultural competence by: centering the client's definition of safety, examining institutional power dynamics, addressing how organizational practices may create unsafe experiences for marginalized groups, and requiring systemic and structural changes—not just individual practitioner skill development.", difficulty: 3, category: "DEI & Anti-Oppressive Practice", topic: "Cultural Safety", questionType: "CASE_VIGNETTE" },
  { id: "sw-532", stem: "An ASWB exam question asks what a social worker should do when they learn that a client's therapist at another agency has been having a sexual relationship with the client. The answer is:", options: ["Do nothing since it involves another agency", "Report the other therapist's conduct to their licensing board, as social workers have an ethical obligation to address unethical conduct by colleagues that harms clients, even across agencies", "Tell the client they must report it themselves", "Ask the other therapist about it directly"], correctIndex: 1, rationale: "Sexual relationships with clients are among the most serious ethical violations. The NASW Code of Ethics requires social workers to address unethical conduct by other professionals when they become aware of it. This obligation extends across agencies. The social worker should report to the appropriate licensing board and support the client through this process.", difficulty: 2, category: "Exam-Style Mixed Practice", topic: "Reporting Ethical Violations", questionType: "MCQ" },
  { id: "sw-533", stem: "The biopsychosocial-spiritual model expands traditional assessment by adding:", options: ["Nothing new to the biopsychosocial model", "A spiritual/existential dimension that considers the client's meaning-making, spiritual beliefs, religious practices, sense of purpose, and how these factors influence their understanding of distress and healing", "A financial assessment only", "A genetic analysis"], correctIndex: 1, rationale: "The biopsychosocial-spiritual model recognizes that spiritual and existential factors significantly influence health, coping, and healing. The spiritual dimension includes: religious/spiritual beliefs and practices, meaning-making and purpose, moral/ethical framework, community of faith, spiritual distress or crisis, and hope. Integrating spirituality respects client wholeness and can strengthen interventions.", difficulty: 2, category: "Assessment & Intervention Planning", topic: "Spiritual Assessment", questionType: "PRIORITIZATION" },
  { id: "sw-534", stem: "A social worker is conducting a risk assessment for intimate partner violence. The MOST important predictor of lethality is:", options: ["The duration of the relationship", "Previous attempts to strangle/choke, escalation of violence severity, access to firearms, and separation/threats of separation", "The couple's socioeconomic status", "The age of the couple"], correctIndex: 1, rationale: "The Campbell Danger Assessment identifies key lethality risk factors: prior strangulation (the single strongest predictor of future homicide), escalating severity, firearm access, threats to kill, forced sex, controlling behavior, and separation/estrangement. Social workers must conduct thorough lethality assessments when domestic violence is present and develop safety plans that address identified risks.", difficulty: 3, category: "Safeguarding & Risk Management", topic: "DV Lethality Assessment", questionType: "PRIORITIZATION" },
  { id: "sw-535", stem: "What does 'trauma-responsive' mean at an organizational level?", options: ["Having trauma-trained therapists on staff", "Embedding trauma-informed principles into all organizational policies, practices, physical environments, and staff interactions so that the entire system promotes safety, trustworthiness, and healing rather than inadvertently causing harm", "Responding to trauma only after it occurs", "A billing category for trauma services"], correctIndex: 1, rationale: "A trauma-responsive organization integrates TIC principles into every aspect of operations: hiring practices, physical environment design, staff training and supervision, policies and procedures, leadership practices, and community engagement. This goes beyond individual clinical practice to transform organizational culture. Assessment tools like the ARTIC (Attitudes Related to Trauma-Informed Care) measure organizational readiness.", difficulty: 2, category: "Trauma-Informed Care", topic: "Organizational Trauma Response", questionType: "CASE_VIGNETTE" },
  { id: "sw-536", stem: "A social worker is evaluating the effectiveness of a prevention program in a school. The MOST appropriate evaluation design for determining causation is:", options: ["Post-test only design", "A quasi-experimental or experimental design comparing outcomes between students who received the program and a comparison group, using pre- and post-measures", "Client satisfaction surveys alone", "Counting the number of students who participated"], correctIndex: 1, rationale: "To determine whether a program causes observed outcomes (rather than other factors), an experimental or quasi-experimental design with a comparison group is needed. Pre-post measures in both groups allow assessment of change attributable to the intervention. While true randomization may not always be feasible in school settings, comparison groups strengthen causal inference.", difficulty: 2, category: "Community Practice", topic: "Program Evaluation Design", questionType: "MCQ" },
  { id: "sw-537", stem: "An ASWB exam question asks about the social worker's BEST response when a client says, 'You don't understand what it's like to be [specific identity].' The answer is:", options: ["'Actually, I do understand because I've studied your culture.'", "'You're right that I haven't had your specific experience. I want to understand your perspective. Can you help me understand what this experience is like for you?'", "'All people are the same regardless of identity.'", "'Maybe you should see a therapist who shares your background.'"], correctIndex: 1, rationale: "This response demonstrates cultural humility by: acknowledging the limitation of the social worker's experience, validating the client's feeling, expressing genuine interest in the client's perspective, and inviting the client to educate the social worker. This approach strengthens the alliance and honors the client's expertise about their own experience. Defensiveness or dismissal damages the therapeutic relationship.", difficulty: 2, category: "Exam-Style Mixed Practice", topic: "Cultural Humility in Practice", questionType: "MCQ" },
  { id: "sw-538", stem: "The concept of 'burnout' was first described by:", options: ["Sigmund Freud", "Herbert Freudenberger, who identified it in human services workers experiencing emotional exhaustion, depersonalization, and reduced personal accomplishment", "Abraham Maslow", "Carl Rogers"], correctIndex: 1, rationale: "Herbert Freudenberger (1974) first described burnout in volunteer workers at a free clinic. Christina Maslach later developed the Maslach Burnout Inventory, identifying three dimensions: emotional exhaustion (feeling drained), depersonalization (cynicism and detachment), and reduced personal accomplishment (feeling ineffective). Understanding burnout is essential for social workers' professional sustainability.", difficulty: 2, category: "Safeguarding & Risk Management", topic: "Burnout Origins", questionType: "PRIORITIZATION" },
  { id: "sw-539", stem: "A social worker is using a harm reduction approach with a client who injects drugs. Specific harm reduction strategies include:", options: ["Requiring immediate abstinence", "Providing education about safer injection practices, connecting to needle exchange programs, distributing naloxone for overdose reversal, offering MAT, and maintaining engagement regardless of continued use", "Refusing services until the client stops using", "Only providing counseling services"], correctIndex: 1, rationale: "Harm reduction for injection drug use includes: syringe exchange programs (reducing blood-borne illness transmission), safer injection education, naloxone distribution and training, fentanyl test strip provision, wound care, MAT engagement, and maintaining the therapeutic relationship regardless of continued use. The goal is to keep clients alive and connected to care.", difficulty: 2, category: "Addictions & Substance Use", topic: "Injection Drug Harm Reduction", questionType: "CASE_VIGNETTE" },
  { id: "sw-540", stem: "An ASWB exam question presents a scenario where a social worker has just completed initial assessment and must determine the appropriate level of care for a client with severe depression and passive suicidal ideation. The BEST answer is:", options: ["Outpatient therapy only since there is no active plan", "Recommend intensive outpatient or partial hospitalization based on the severity of symptoms, functional impairment, support system availability, and whether the client can maintain safety in a less restrictive setting", "Immediate inpatient hospitalization for all clients with suicidal ideation", "Discharge with a referral to their primary care physician"], correctIndex: 1, rationale: "Level of care decisions consider: symptom severity, functional impairment, safety risk, support system, treatment history, client preferences, and available resources. Severe depression with passive ideation may not require inpatient care if the client has adequate support and safety. IOP or PHP provides intensive treatment while maintaining community connections. The least restrictive effective level of care is the standard.", difficulty: 2, category: "Exam-Style Mixed Practice", topic: "Level of Care Determination", questionType: "MCQ" },
  { id: "sw-541", stem: "What is the 'social work grand challenge' related to health equity?", options: ["Providing healthcare to the wealthy", "Closing the health gap by addressing social, economic, and environmental factors that create health disparities across racial, ethnic, socioeconomic, and geographic lines", "Building more hospitals", "Training more physicians"], correctIndex: 1, rationale: "The American Academy of Social Work and Social Welfare's Grand Challenges include 'Close the Health Gap,' which calls on social workers to address the social, economic, and environmental conditions that create health disparities. Social workers are uniquely positioned to address health equity through clinical practice, community organizing, policy advocacy, and research on social determinants of health.", difficulty: 2, category: "Social Determinants of Health", topic: "Health Equity Grand Challenge", questionType: "MCQ" },
  { id: "sw-542", stem: "What is the social worker's role in addressing vaccine hesitancy in underserved communities?", options: ["Forcing vaccination compliance", "Providing culturally sensitive education, addressing historical mistrust, using motivational interviewing to explore ambivalence, connecting to trusted community leaders and healthcare providers, and respecting client autonomy", "Ignoring the issue as outside scope", "Only providing information from government websites"], correctIndex: 1, rationale: "Vaccine hesitancy in underserved communities often stems from legitimate historical concerns (Tuskegee, forced sterilization), healthcare access barriers, cultural beliefs, and institutional distrust. Social workers should: acknowledge historical context, provide balanced evidence-based information, use MI to explore concerns, connect to trusted community voices, and respect client autonomy while advocating for equitable access.", difficulty: 2, category: "Community Practice", topic: "Health Education", questionType: "MCQ" },
  { id: "sw-543", stem: "An ASWB exam question asks what a social worker should do when they feel sexually attracted to a client. The correct answer is:", options: ["Act on the feelings since they may be mutual", "Seek immediate supervision or personal therapy to process the feelings, maintain professional boundaries, and consider whether the attraction impairs the ability to provide competent care", "Ignore the feelings and continue treatment", "Disclose the feelings to the client to be transparent"], correctIndex: 1, rationale: "Sexual attraction to clients is a normal human experience that requires professional management. The ethical response is to: seek supervision or personal therapy, process the countertransference, maintain strict professional boundaries, assess whether the attraction impairs clinical judgment, and transfer the client if necessary. Acting on sexual feelings toward a client is one of the most serious ethical violations.", difficulty: 2, category: "Exam-Style Mixed Practice", topic: "Managing Attraction", questionType: "MCQ" },
  { id: "sw-544", stem: "A social worker is working with a client who has been diagnosed with a terminal illness. The client is experiencing anticipatory grief. This is best described as:", options: ["Grief that occurs only after the person has died", "The process of mourning expected losses before they occur, including loss of health, future plans, relationships, roles, and ultimately life itself", "Excessive worrying about future events", "A pathological grief response requiring hospitalization"], correctIndex: 1, rationale: "Anticipatory grief involves mourning expected losses before they occur. For terminally ill clients, this includes grieving loss of health, independence, future milestones, identity/roles, and relationships. For family members, it includes grieving the anticipated death. Anticipatory grief can be therapeutic, allowing emotional preparation, life completion work, and meaningful goodbye. It does not reduce post-death grief but may facilitate adaptation.", difficulty: 2, category: "Gerontology", topic: "Anticipatory Grief", questionType: "CASE_VIGNETTE" },
  { id: "sw-545", stem: "A social worker is working in a school that uses Positive Behavioral Interventions and Supports (PBIS). This framework:", options: ["Relies primarily on punitive discipline", "Uses a tiered approach—universal prevention for all students, targeted interventions for at-risk students, and intensive individualized support for students with significant behavioral challenges", "Applies only to students with disabilities", "Eliminates all consequences for behavior"], correctIndex: 1, rationale: "PBIS is an evidence-based, multi-tiered framework: Tier 1 provides universal prevention (school-wide expectations, positive reinforcement, consistent responses) for all students. Tier 2 provides targeted group interventions for at-risk students. Tier 3 provides intensive, individualized support (functional behavioral assessment, behavior intervention plans) for students with significant needs. PBIS reduces disciplinary actions and improves school climate.", difficulty: 2, category: "School & Social Service Systems", topic: "PBIS Framework", questionType: "MCQ" },
  { id: "sw-546", stem: "Solution-focused brief therapy was developed by:", options: ["Sigmund Freud", "Steve de Shazer and Insoo Kim Berg at the Brief Family Therapy Center in Milwaukee", "Aaron Beck", "Albert Ellis"], correctIndex: 1, rationale: "SFBT was developed by Steve de Shazer and Insoo Kim Berg at the Brief Family Therapy Center in Milwaukee in the 1980s. It represents a paradigm shift from problem-focused to solution-focused practice. Key principles include: if it ain't broke, don't fix it; if it works, do more of it; if it doesn't work, do something different. SFBT has evidence for various populations and settings.", difficulty: 1, category: "Clinical Practice", topic: "SFBT Origins", questionType: "CASE_VIGNETTE" },
  { id: "sw-547", stem: "What is the purpose of a functional behavioral assessment (FBA) in a school setting?", options: ["To punish the student for misbehavior", "To identify the antecedents, behaviors, and consequences (ABC) that maintain a student's challenging behavior, informing the development of a positive behavior intervention plan", "To diagnose a mental health disorder", "To determine the student's IQ"], correctIndex: 1, rationale: "FBA in schools systematically examines the function of challenging behavior by identifying triggers (antecedents), describing the behavior, and analyzing what maintains it (consequences/reinforcers). This analysis reveals whether the behavior serves to obtain something (attention, tangible items) or avoid/escape something (tasks, social situations). The FBA informs the development of a behavior intervention plan (BIP).", difficulty: 2, category: "School & Social Service Systems", topic: "School-Based FBA", questionType: "MCQ" },
  { id: "sw-548", stem: "An ASWB question asks about the most important principle when working with involuntary clients. The BEST answer is:", options: ["Force compliance with treatment goals", "Respect client dignity, acknowledge the involuntary nature of the mandate, find areas where the client's goals can align with mandated requirements, and use engagement strategies that promote internal motivation", "Lower expectations for treatment outcomes", "Avoid building a therapeutic relationship since the client doesn't want to be there"], correctIndex: 1, rationale: "Working with involuntary clients requires: acknowledging the mandate honestly, respecting the client's dignity despite the coercive context, exploring areas where the client's own goals may align with mandated requirements, using motivational interviewing to build intrinsic motivation, and maintaining hope for positive outcomes. Research shows that even mandated clients can benefit from treatment when engagement is skillful.", difficulty: 2, category: "Exam-Style Mixed Practice", topic: "Involuntary Clients", questionType: "MCQ" },
  { id: "sw-549", stem: "Social constructionism in social work theory proposes that:", options: ["Reality is entirely objective and fixed", "Knowledge and meaning are socially constructed through language, culture, and interaction—what we understand as 'problems,' 'illness,' and 'normal' are shaped by social context rather than being purely objective categories", "Individual psychology determines all social phenomena", "Social constructs have no practical implications"], correctIndex: 1, rationale: "Social constructionism (Berger & Luckmann, Gergen) posits that knowledge, meaning, and reality are constructed through social processes. In social work, this means: diagnostic categories, definitions of 'normal' behavior, and conceptualizations of social problems are culturally constructed. This perspective encourages questioning dominant narratives, valuing diverse perspectives, and understanding how language shapes experience.", difficulty: 2, category: "Clinical Practice", topic: "Social Constructionism", questionType: "CASE_VIGNETTE" },
  { id: "sw-550", stem: "An ASWB question asks: When is it appropriate for a social worker to self-disclose personal information to a client?", options: ["Whenever the social worker feels like sharing", "When the self-disclosure serves a clear therapeutic purpose, is brief, and shifts the focus back to the client—such as normalizing an experience or building rapport—without burdening the client with the social worker's needs", "Never under any circumstances", "Only if the client asks a direct question"], correctIndex: 1, rationale: "Self-disclosure is a clinical tool that can be therapeutic when used judiciously. Guidelines include: it must serve the client's therapeutic goals (not the worker's needs), be brief and purposeful, redirect focus to the client, avoid detailed personal information, and consider the client's vulnerabilities. Appropriate examples include normalizing experiences, building hope, or bridging cultural differences.", difficulty: 2, category: "Exam-Style Mixed Practice", topic: "Therapeutic Self-Disclosure", questionType: "MCQ" },
];
